import { promises as fsPromises } from 'fs/promises';
import { resolve, join } from 'src/utils/path';

// Define the base storage path for the application
const STORAGE_BASE_PATH = resolve(process.env.HOME || '', '.yourAppName'); // Adjust the path as necessary

// Ensure the storage base path exists
async function ensureStorageBasePath() {
    try {
        await fsPromises.mkdir(STORAGE_BASE_PATH, { recursive: true });
    } catch (error) {
        console.error('Could not create storage base path:', error);
    }
}

/**
 * Get the base storage path.
 */
export async function getStorageBasePath(): Promise<string> {
    await ensureStorageBasePath();
    return STORAGE_BASE_PATH;
}

/**
 * Get the task directory path within the storage base path.
 */
export async function getTaskDirectoryPath(): Promise<string> {
    const basePath = await getStorageBasePath();
    const taskDir = join(basePath, 'tasks');
    await fsPromises.mkdir(taskDir, { recursive: true });
    return taskDir;
}

/**
 * Get the settings directory path within the storage base path.
 */
export async function getSettingsDirectoryPath(): Promise<string> {
    const basePath = await getStorageBasePath();
    const settingsDir = join(basePath, 'settings');
    await fsPromises.mkdir(settingsDir, { recursive: true });
    return settingsDir;
}

/**
 * Get the cache directory path within the storage base path.
 */
export async function getCacheDirectoryPath(): Promise<string> {
    const basePath = await getStorageBasePath();
    const cacheDir = join(basePath, 'cache');
    await fsPromises.mkdir(cacheDir, { recursive: true });
    return cacheDir;
}

/**
 * Prompt the user for a custom storage path using the VSCode API.
 */
export async function promptForCustomStoragePath(): Promise<string | undefined> {
    const result = await vscode.window.showInputBox({
        placeHolder: i18n('EnterCustomStoragePath'),
        prompt: i18n('ProvideAPath'),
    });

    if (result) {
        try {
            await fsPromises.mkdir(result, { recursive: true });
            return result;
        } catch (error) {
