/**
 * Gets the directory of the current module.
 */
export function getModuleDir(): string {
  return __dirname;
}

/**
 * Finds the esbuild WASM script file by scanning the module directory.
 */
export function findEsbuildWasmScript(dir: string): string | null {
  const files = readDirectory(dir);
  const wasmScripts = files.filter(file => file.endsWith('.wasm'));
  return wasmScripts.length > 0 ? resolve(dir, wasmScripts[0]) : null;
}

/**
 * Gets the path to the esbuild script.
 */
export function getEsbuildScriptPath(): string {
  const moduleDir = getModuleDir();
  const esbuildPath = findEsbuildWasmScript(moduleDir);
  if (!esbuildPath) {
    throw new Error('esbuild WASM script not found in module directory.');
  }
  return esbuildPath;
}

/**
 * Runs the esbuild command with specified arguments.
 */
export async function runEsbuild(args: string[]): Promise<void> {
  const esbuildPath = getEsbuildScriptPath();
  try {
    await execa(esbuildPath, args);
  } catch (error) {
    console.error('Failed to run esbuild:', error);
    throw error;
  }
}
```

