export function convertGitUrlToHttps(gitUrl) {
    if (gitUrl.startsWith('git@')) {
        return gitUrl
            .replace('git@github.com:', 'https://github.com/')
            .replace('.git', '');
    }
    return gitUrl;
}

// Sanitize a Git URL
export function sanitizeGitUrl(gitUrl) {
    // Remove any unwanted parameters or malformed parts of the URL
    return gitUrl.replace(/[^a-zA-Z0-9/:._-]/g, ''); // Example regex for sanitizing
}

// Extract the repository name from a Git URL
